import React, { useState, useRef } from 'react';
import { classifyWaste, IMPACT } from '../services/api';
import { addRecord } from '../services/store';
import ResultCard from '../components/ResultCard';
import ImpactPanel from '../components/ImpactPanel';
import './Home.css';

export default function Home() {
  const [preview, setPreview]   = useState(null);
  const [file, setFile]         = useState(null);
  const [loading, setLoading]   = useState(false);
  const [result, setResult]     = useState(null);
  const [error, setError]       = useState('');
  const [toast, setToast]       = useState(null);
  const inputRef = useRef();

  function showToast(msg, type = 'success') {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  }

  function handleFileChange(e) {
    const f = e.target.files[0];
    if (!f) return;
    if (!f.type.startsWith('image/')) {
      showToast('Please select an image file', 'error');
      return;
    }
    setFile(f);
    setResult(null);
    setError('');
    const reader = new FileReader();
    reader.onload = ev => setPreview(ev.target.result);
    reader.readAsDataURL(f);
  }

  async function handleSubmit(e) {
    e.preventDefault();
    if (!file) { showToast('Please choose or capture an image first', 'error'); return; }

    setLoading(true);
    setError('');
    setResult(null);

    try {
      const data = await classifyWaste(file);
      const category = data.prediction;
      const impact   = IMPACT[category];
      if (!impact) throw new Error('Unknown category: ' + category);

      const record = addRecord(category, impact.guidance);
      setResult({ category, impact, record });
      showToast('Classification complete! ✅');
    } catch (err) {
      setError(err.message || 'Something went wrong. Is the server running?');
      showToast(err.message || 'Error', 'error');
    } finally {
      setLoading(false);
    }
  }

  function handleReset() {
    setPreview(null);
    setFile(null);
    setResult(null);
    setError('');
    if (inputRef.current) inputRef.current.value = '';
  }

  return (
    <div className="page-content home-page">
      {/* Header */}
      <header className="home-header">
        <div className="logo-badge">🌿</div>
        <div>
          <h1 className="home-title">EcoScan</h1>
          <p className="home-subtitle">AI Waste Classifier</p>
        </div>
      </header>

      {/* Hero / Upload Section */}
      <section className="upload-section">
        {!preview ? (
          <div className="upload-cta">
            <div className="upload-hero-icon">📷</div>
            <h2 className="upload-heading">Scan Your Waste</h2>
            <p className="upload-desc">
              Take a photo or upload an image to instantly identify waste type and get disposal guidance.
            </p>

            <div className="upload-buttons">
              {/* Camera button – opens camera directly on mobile */}
              <label className="btn btn-primary" htmlFor="camera-input">
                📸 Open Camera
              </label>
              <input
                id="camera-input"
                type="file"
                accept="image/*"
                capture="environment"
                hidden
                ref={inputRef}
                onChange={handleFileChange}
              />

              {/* Gallery upload */}
              <label className="btn btn-outline" htmlFor="gallery-input">
                🖼️ Upload Image
              </label>
              <input
                id="gallery-input"
                type="file"
                accept="image/*"
                hidden
                onChange={handleFileChange}
              />
            </div>

            <p className="upload-hint">Supports JPG, PNG, WEBP • Max 10 MB</p>
          </div>
        ) : (
          <div className="preview-section">
            <div className="preview-wrapper">
              <img src={preview} alt="Selected waste" className="preview-img" />
              <button className="preview-clear" onClick={handleReset}>✕</button>
            </div>

            {!result && (
              <form onSubmit={handleSubmit}>
                <button type="submit" className="btn btn-primary btn-full" disabled={loading}>
                  {loading ? <><span className="btn-spinner" /> Analysing…</> : '🔍 Classify Waste'}
                </button>
              </form>
            )}
          </div>
        )}
      </section>

      {/* Loading overlay */}
      {loading && (
        <div className="loading-overlay">
          <div className="loading-card">
            <div className="spinner" />
            <p className="loading-text">AI is analysing your waste…</p>
            <p className="loading-sub">This takes just a moment</p>
          </div>
        </div>
      )}

      {/* Error */}
      {error && (
        <div className="error-banner">
          <span>⚠️ {error}</span>
        </div>
      )}

      {/* Result */}
      {result && (
        <>
          <ResultCard category={result.category} impact={result.impact} />
          <ImpactPanel impact={result.impact} single />
          <div className="scan-again-wrap">
            <button className="btn btn-outline" onClick={handleReset}>
              📷 Scan Another Item
            </button>
          </div>
        </>
      )}

      {/* How it works */}
      {!preview && !result && (
        <section className="how-section">
          <h3 className="section-title">How It Works</h3>
          <div className="steps">
            {[
              { icon: '📷', title: 'Capture', desc: 'Take a photo with your camera or upload from gallery.' },
              { icon: '🤖', title: 'AI Analyse', desc: 'Our model classifies the waste in under a second.' },
              { icon: '♻️', title: 'Act Right', desc: 'Get bin guidance and environmental impact insights.' },
            ].map((s, i) => (
              <div className="step-card" key={i}>
                <div className="step-icon">{s.icon}</div>
                <h4 className="step-title">{s.title}</h4>
                <p className="step-desc">{s.desc}</p>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Toast */}
      {toast && <div className={`toast ${toast.type}`}>{toast.msg}</div>}
    </div>
  );
}
